import{c as i,Q as t,j as r,g as a,n as o}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"论小洛伦佐去世后佛罗伦","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/211-论小洛伦佐去世后佛罗伦.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/211-论小洛伦佐去世后佛罗伦.md"}'),l={name:"research/machiavelli/machiavelli/diplomatic/lower/211-论小洛伦佐去世后佛罗伦.md"};function c(n,e,d,s,m,_){return t(),r("div",null,[...e[0]||(e[0]=[a("h1",{id:"论小洛伦佐去世后佛罗伦",tabindex:"-1"},[o("论小洛伦佐去世后佛罗伦 "),a("a",{class:"header-anchor",href:"#论小洛伦佐去世后佛罗伦","aria-label":'Permalink to "论小洛伦佐去世后佛罗伦"'},"​")],-1),a("p",null,'论小洛伦佐去世后佛罗伦萨的政务 野心。纠正的方法如下：废除执政团、 "外务八人委员会”和“十二贤 人团”;①作为替代，也是为了赋予政府以威严，任命65位45岁以上的公 民，组成“六十五人委员会”:其中，53人来自主要行会，12人来自次要 行会。他们以下述方式终身任职：从确定的人数中挑选出一位担任正义旗 手2-3年，除非他适合终身任职；剩下的64位公民分为两组，每组32人， 一组辅佐正义旗手1年，另外一组下一年辅佐；他们按照下文指定的安排 轮流交替。所有这些人一起合称执政团。这32人又细分为四小组，8人一 组。每个小组与正义旗手一同居住在市政宫官邸内3个月；按照传统的仪 式任命行政长官，处理执政团当天要独立处理的一切事务。自此，它连同 另外32位同僚，享有(前面建议废除的)执政团、 “外务八人委员会”、 顾问团的一切权威，处理它们当天所要处理的一切事务。如我所说，这 (“六十五人委员会”)就是政府的首脑及其主要成员。如果说这一安排 是经过深思熟虑的，那么,它将会被视为赋予政府首脑以威严与影响；因 为，声名显赫的大人物显然将始终占据最高职位。再也没有必要去咨询私 人——我在前面说过，这在一个共和国是有害的——因为，当年没有担任 行政长官的32人可以提供建言和咨询。正如我下面将要解释的，陛下您也 可以在这第一轮遴选中安插您所有的朋友与可信赖的追随者。不过，还是 让我们来看看政府的第二等级吧。 如前所述，既然存在三种类型的人，那么我认为，有必要在共和国里 不多不少正好划分出三个等级。因此，我深信，裁汰那些在您的城邦里存 在已经有些时日的各类委员会是大有裨益的。成立这些委员会不是因为它 们对于一个良好的政府来说是不可或缺的，而是因它们能够满足公民们膨',-1),a("p",null,"①1480年4月洛伦佐 · 德 · 梅迪奇在佛罗伦萨推行改革，通过巴利阿成立新的机构“七十人会议” (Consiglio dei Settanta), 并从中选出两个新的机构“外务八人委员会” ( Otto di Pratica/Otto della Pratica) 和“十二人行政委员会” ( Dodici Procuratori), 分别负责外交和内政(尤其是金融)事务。 由此，它成为佛罗伦萨的最高决策机构。对于它的两个下属机构，不要混淆于传统的“十二贤人团” ( Dodici Buonuomini, 执政团的顾问机构)和“公安八人委员会”( Otto di Guardia/Otto di guardia e balia, 负责警务的司法委员会)。七十人会议和外务八人委员会在1494年被废除，直到1512年梅迪奇家族 复辟后恢复。 — 中译者注",-1),a("p",null,"Legazioni,commissarie,scritti di governo",-1)])])}const u=i(l,[["render",c]]);export{h as __pageData,u as default};
